// Spanish question bank — index-aligned with BANK in questions.js.
// Terminology follows FL Spanish prelicense course usage (see repo history for sources).
export const BANK_ES = [
{t:"FREC",q:"¿Cuántos miembros integran la Comisión de Bienes Raíces de la Florida (FREC)?",o:["5","7","9","11"],e:"Siete miembros nombrados por el Gobernador y confirmados por el Senado: cuatro corredores licenciados, un corredor o asociado de ventas y dos miembros consumidores. Los mandatos son de 4 años."},
{t:"FREC",q:"¿Cuántos miembros de la FREC deben ser miembros consumidores que nunca hayan tenido una licencia de bienes raíces?",o:["Uno","Dos","Tres","Cuatro"],e:"Dos miembros nunca deben haber sido licenciatarios, y al menos un comisionado debe tener 60 años de edad o más."},
{t:"FREC",q:"¿Cuál es un poder cuasi judicial de la FREC?",o:["Adoptar reglas administrativas","Suspender o revocar una licencia","Fijar las cuotas de licencia","Educar a los licenciatarios"],e:"Disciplinar a los licenciatarios (multas, suspensión, revocación) es una función cuasi judicial. La adopción de reglas y la fijación de cuotas son poderes cuasi legislativos."},
{t:"Disciplina",q:"El período máximo por el cual la FREC puede suspender una licencia es:",o:["2 años","5 años","10 años","Permanentemente"],e:"La suspensión no puede exceder 10 años. La revocación es generalmente permanente."},
{t:"Licencias",q:"¿Cuántas horas de educación de prelicencia (Curso I de la FREC) debe completar un solicitante de asociado de ventas?",o:["45 horas","63 horas","72 horas","14 horas"],e:"63 horas más aprobar el examen de fin de curso. Las 45 horas son el requisito de poslicencia; las 72 horas son la prelicencia de corredor; las 14 horas son la educación continua."},
{t:"Licencias",q:"Un asociado de ventas que no completa el curso de poslicencia de 45 horas antes de la primera renovación de su licencia:",o:["Puede renovar pagando un cargo por demora","Tiene una licencia que se vuelve nula y sin efecto","Es colocado en estado inactivo involuntario por 2 años","Completa 14 horas de educación continua en su lugar"],e:"La licencia se vuelve nula y sin efecto. Para ejercer de nuevo, la persona debe calificar nuevamente como solicitante nuevo, retomando el curso de 63 horas y el examen estatal."},
{t:"Licencias",q:"Después de la primera renovación, ¿cuánta educación continua debe completar un asociado de ventas en cada período de licencia de 2 años?",o:["45 horas","28 horas","14 horas","63 horas"],e:"14 horas de educación continua, incluyendo un componente de ley fundamental (core law), en cada ciclo de renovación de 2 años después de la primera renovación."},
{t:"Licencias",q:"¿Cuál es un requisito para obtener la licencia de asociado de ventas de la Florida?",o:["Residencia en la Florida","Ciudadanía de los EE. UU.","Tener al menos 18 años y un diploma de escuela secundaria o su equivalente","Un título universitario"],e:"Los solicitantes deben tener al menos 18 años, poseer un diploma de escuela secundaria o su equivalente y tener un número de Seguro Social. La residencia en la Florida y la ciudadanía estadounidense no son requisitos."},
{t:"Licencias",q:"Una licencia que permanece inactiva involuntaria por más de 2 años:",o:["Se renueva automáticamente","Se vuelve nula y sin efecto","Se convierte a estado inactivo voluntario","Puede reactivarse con 14 horas de educación continua"],e:"Después de 2 años en estado inactivo involuntario la licencia expira. Dentro de los primeros 12 meses, 14 horas de educación continua la reactivan; entre los 12 y 24 meses, se requiere un curso de reactivación de 28 horas."},
{t:"Licencias",q:"Una licencia de bienes raíces de la Florida debe renovarse cada:",o:["Año","2 años","3 años","4 años"],e:"Las licencias se emiten por períodos de 2 años que vencen el 31 de marzo o el 30 de septiembre."},
{t:"Licencias",q:"Un licenciatario de un estado con reconocimiento mutuo puede obtener una licencia de la Florida aprobando un examen de leyes de la Florida que consiste en:",o:["100 preguntas, 75 correctas para aprobar","40 preguntas, 30 correctas para aprobar","50 preguntas, 38 correctas para aprobar","No se requiere examen"],e:"Los solicitantes por reconocimiento mutuo toman un examen de 40 preguntas sobre las leyes de la Florida y deben contestar correctamente al menos 30 (75%)."},
{t:"Licencias",q:"¿Por cuánto tiempo permanece válida una solicitud de licencia después de ser recibida por el DBPR?",o:["6 meses","1 año","2 años","5 años"],e:"La solicitud es válida por 2 años. El solicitante debe aprobar el examen estatal dentro de ese período."},
{t:"Licencias",q:"Un asociado de ventas empleado por un propietario-desarrollador con varias subsidiarias afiliadas, que vende únicamente las propiedades del desarrollador, debe tener:",o:["Licencias múltiples","Una licencia de grupo","Una licencia de corredor","No se necesita licencia"],e:"Una licencia de grupo permite a un asociado de ventas trabajar para entidades afiliadas bajo un mismo propietario-desarrollador. Las licencias múltiples solo están disponibles para corredores."},
{t:"Licencias",q:"¿Cuál licenciatario puede tener licencias múltiples?",o:["Un asociado de ventas que trabaja para dos corredores","Un corredor que califica entidades de corretaje separadas","Un corredor asociado","Cualquier licenciatario con aprobación de la FREC"],e:"Solo los corredores pueden tener licencias múltiples, una por cada compañía en la que actúan como corredor. Los asociados de ventas solo pueden tener un empleador."},
{t:"Plica",q:"Un asociado de ventas recibe un depósito de buena fe (arras) el miércoles. El depósito debe ser entregado al corredor empleador a más tardar al final de:",o:["El mismo miércoles (día hábil)","El siguiente día hábil (jueves)","El tercer día hábil","El día anterior al cierre"],e:"Un asociado de ventas debe entregar los fondos de plica al corredor a más tardar al final del siguiente día hábil después de recibirlos."},
{t:"Plica",q:"Un corredor debe depositar los fondos de plica en la cuenta de plica a más tardar:",o:["Al final del siguiente día hábil","Al final del tercer día hábil después de que el licenciatario recibió los fondos","5 días hábiles después de recibirlos","El día del cierre"],e:"El depósito se requiere a más tardar al final del tercer día hábil siguiente a la recepción de los fondos por la firma de corretaje."},
{t:"Plica",q:"Un corredor recibe demandas contradictorias sobre un depósito de plica en disputa. El corredor debe notificar a la FREC por escrito dentro de:",o:["10 días hábiles","15 días hábiles","30 días hábiles","45 días calendario"],e:"La notificación a la FREC debe hacerse dentro de los 15 días hábiles siguientes a la última demanda contradictoria, y un procedimiento de resolución debe iniciarse dentro de los 30 días hábiles."},
{t:"Plica",q:"¿Cuál procedimiento de resolución de disputas de plica es conducido por la propia FREC?",o:["Mediación","Arbitraje","Litigio","Orden de desembolso de plica"],e:"La FREC emite órdenes de desembolso de plica (EDO) que indican quién recibe los fondos de plica de venta en disputa retenidos por un corredor. La mediación, el arbitraje y el litigio involucran a terceros o a los tribunales."},
{t:"Fondo de Recuperación",q:"El pago máximo del Fondo de Recuperación de Bienes Raíces por una sola transacción es:",o:["$25,000","$50,000","$150,000","$500,000"],e:"$50,000 por transacción y $150,000 en total contra un mismo licenciatario por reclamaciones múltiples."},
{t:"Fondo de Recuperación",q:"Cuando el Fondo de Recuperación paga una sentencia contra un licenciatario, la licencia queda:",o:["Revocada permanentemente","Suspendida automáticamente hasta que el fondo sea reembolsado con intereses","Sin afectación","En período de prueba por 2 años"],e:"La licencia se suspende automáticamente y no se restablece hasta que el licenciatario reembolse el fondo en su totalidad, más intereses."},
{t:"Disciplina",q:"Realizar servicios de bienes raíces por compensación sin licencia en la Florida es:",o:["Un delito menor de segundo grado","Un delito menor de primer grado","Un delito grave de tercer grado","Solo una infracción civil"],e:"La actividad sin licencia es un delito grave de tercer grado, castigable con una multa de hasta $5,000 y hasta 5 años de prisión."},
{t:"Disciplina",q:"La multa administrativa máxima que la FREC puede imponer es:",o:["$500 por cargo","$1,000 por cargo","$5,000 por cargo","$10,000 por cargo"],e:"La FREC puede imponer una multa administrativa de hasta $5,000 por cada cargo u ofensa separada."},
{t:"Disciplina",q:"Por una violación menor cometida por primera vez que no causa daño al consumidor, lo más probable es que el DBPR emita:",o:["Una queja formal","Un aviso de incumplimiento","Una suspensión sumaria","Una orden de revocación"],e:"Un aviso de incumplimiento es una advertencia por una violación menor cometida por primera vez. Las citaciones con multas establecidas aplican a otras violaciones menores especificadas."},
{t:"Disciplina",q:"Una queja presentada ante el DBPR es \"legalmente suficiente\" si:",o:["Está notariada","Alega una violación de un estatuto de la Florida, una regla del DBPR o una regla de la FREC","Es presentada por un residente de la Florida","Involucra daños de más de $5,000"],e:"La suficiencia legal significa que los hechos alegados, de ser ciertos, violarían la ley o las reglas. Las quejas anónimas pueden calificar bajo ciertas condiciones."},
{t:"Disciplina",q:"La causa probable en un caso disciplinario es determinada por:",o:["La Comisión completa de siete miembros","Un panel de causa probable de al menos dos miembros de la FREC","El director de la División de Bienes Raíces","Un juez de un tribunal de circuito"],e:"Un panel de al menos dos comisionados revisa el informe de investigación y decide si existe causa probable para presentar una queja formal."},
{t:"Disciplina",q:"Un licenciatario que desea apelar una orden final de la FREC debe solicitar revisión judicial dentro de:",o:["10 días","20 días","30 días","90 días"],e:"La petición de revisión debe presentarse ante el tribunal de apelaciones de distrito dentro de los 30 días posteriores a la emisión de la orden final."},
{t:"Disciplina",q:"Un licenciatario declarado culpable de un delito debe notificar al DBPR dentro de cuántos días de la condena o declaración:",o:["10 días","30 días","60 días","90 días"],e:"Se requiere notificación por escrito dentro de los 30 días de ser condenado o declarado culpable de un delito, o de declararse culpable o nolo contendere."},
{t:"Oficina y Registros",q:"Un licenciatario que cambia su dirección de residencia debe notificar al DBPR dentro de:",o:["48 horas","10 días","30 días","60 días"],e:"Los cambios de dirección deben reportarse dentro de 10 días."},
{t:"Oficina y Registros",q:"Los corredores deben conservar los registros de transacciones y de plica (escrow) durante al menos:",o:["2 años","3 años","5 años","7 años"],e:"Los registros deben conservarse durante 5 años, o 2 años después de concluido un litigio si este se extiende más allá de ese período."},
{t:"Oficina y Registros",q:"El letrero en la entrada de la oficina de un corredor debe incluir:",o:["El nombre del corredor, el nombre comercial si lo hay, y las palabras Licensed Real Estate Broker","Solo el nombre comercial","Los nombres de todos los asociados de ventas","Solo el número de licencia del corredor"],e:"El letrero debe mostrar el nombre del corredor, el nombre comercial (si se usa uno) y las palabras 'Licensed Real Estate Broker' o 'Lic. Real Estate Broker'."},
{t:"Publicidad",q:"Un anuncio que no incluye el nombre licenciado de la firma de corretaje es:",o:["Permitido para alquileres","Un anuncio ciego, lo cual está prohibido","Permitido solo en internet","Legal si aparece el nombre del asociado"],e:"Toda la publicidad de corretaje debe incluir el nombre licenciado de la firma de corretaje; omitirlo crea un anuncio ciego ilegal."},
{t:"Compensación",q:"Un asociado de ventas puede recibir legalmente compensación de bienes raíces de:",o:["Cualquier parte de la transacción","Únicamente el corredor que lo emplea","La compañía de título","El corredor de otra firma de corretaje"],e:"Los asociados de ventas y los corredores asociados solo pueden recibir pago del corredor (o de la entidad de corretaje) bajo el cual están registrados."},
{t:"Compensación",q:"¿Cuál pago es legal?",o:["Una división de la comisión con un amigo sin licencia por un referido","Un reembolso (rebate) divulgado a un comprador en la transacción, pagado a través del corredor","Un honorario pagado directamente al asociado de ventas de otra firma","Un bono del vendedor pagado directamente al asociado de ventas"],e:"Los reembolsos (rebates) a una parte de la transacción son legales si se divulgan completamente a todas las partes interesadas. Compartir compensación con personas sin licencia por servicios de bienes raíces es ilegal."},
{t:"Relaciones de Corretaje",q:"En la Florida, se presume que un licenciatario opera como:",o:["Agente único","Corredor de transacciones","No representante","Agente designado"],e:"El corretaje de transacciones es la relación que se presume, a menos que se establezca por escrito una relación de agente único o sin relación de corretaje."},
{t:"Relaciones de Corretaje",q:"¿Cuál de los siguientes deberes tiene un agente único pero NO un corredor de transacciones?",o:["Trato honesto y justo","Lealtad","Rendición de cuentas de todos los fondos","Destreza, cuidado y diligencia"],e:"Los agentes únicos deben deberes fiduciarios a su principal, incluidos lealtad, obediencia y confidencialidad plena. Un corredor de transacciones solo debe confidencialidad limitada y no debe lealtad."},
{t:"Relaciones de Corretaje",q:"¿Cuántos deberes estatutarios le debe un agente único al principal?",o:["3","7","9","12"],e:"Nueve deberes, que incluyen lealtad, confidencialidad, obediencia, divulgación completa, rendición de cuentas, destreza/cuidado/diligencia, presentar todas las ofertas, divulgar los hechos conocidos que afectan materialmente el valor de una propiedad residencial, y trato honesto y justo. Un corredor de transacciones debe siete; sin relación de corretaje, tres."},
{t:"Relaciones de Corretaje",q:"Antes de cambiar de agente único a corredor de transacciones con el mismo cliente, un licenciatario debe obtener:",o:["La aprobación de la FREC","El consentimiento del principal, firmado o con iniciales en la divulgación de transición","Una orden judicial","Nada; el cambio es automático"],e:"El texto de consentimiento para la transición debe ser firmado o marcado con iniciales por el principal antes de que el licenciatario pueda hacer el cambio."},
{t:"Relaciones de Corretaje",q:"¿Qué deber se le debe a un cliente incluso bajo una relación de 'sin relación de corretaje'?",o:["Lealtad","Obediencia","Divulgar los hechos conocidos que afectan materialmente el valor de una propiedad residencial y que no son fácilmente observables","Presentar todas las ofertas"],e:"Los tres deberes cuando no hay relación de corretaje son: trato honesto y justo, divulgar los hechos materiales conocidos sobre la propiedad residencial y rendición de cuentas de todos los fondos."},
{t:"Relaciones de Corretaje",q:"Los asociados de ventas designados pueden nombrarse únicamente en:",o:["Ventas residenciales de cualquier precio","Transacciones no residenciales en las que el comprador y el vendedor tienen cada uno activos de al menos $1 millón","Arrendamientos comerciales de más de $5 millones","Transacciones que involucran partes de fuera del estado"],e:"Dos asociados del mismo corredor pueden actuar como agentes únicos para partes opuestas solo en transacciones no residenciales en las que cada parte tiene $1 millón o más en activos y solicita el arreglo por escrito."},
{t:"Relaciones de Corretaje",q:"En una venta residencial, la divulgación de agente único debe entregarse:",o:["Al cierre","Antes o al momento de celebrar un contrato de listado o de representación, o antes de mostrar la propiedad, lo que ocurra primero","Dentro de los 3 días después de firmarse un contrato","Solo si el cliente la solicita"],e:"Las divulgaciones escritas de agente único (y de sin relación de corretaje) se requieren en las ventas residenciales antes de estos primeros puntos de contacto o al momento de ellos."},
{t:"Vivienda Justa",q:"¿Qué clases protegidas añadieron las enmiendas de 1988 a la Ley de Vivienda Justa federal?",o:["Raza y color","Religión y sexo","Estado familiar y discapacidad (handicap)","Edad y estado civil"],e:"La ley original de 1968 cubría raza, color, religión y origen nacional; el sexo se añadió en 1974; el estado familiar y la discapacidad se añadieron en 1988."},
{t:"Vivienda Justa",q:"La Ley de Derechos Civiles de 1866:",o:["Aplica solo a viviendas con financiamiento federal","Prohíbe la discriminación racial en todas las transacciones de propiedad, sin excepciones","Permite exenciones para propietarios-ocupantes","Cubre religión y sexo"],e:"La ley de 1866 prohíbe toda discriminación racial en las transacciones de bienes inmuebles, sin exenciones, según se confirmó en Jones v. Mayer (1968)."},
{t:"Vivienda Justa",q:"Canalizar a compradores potenciales hacia ciertos vecindarios, o alejarlos de ellos, con base en una clase protegida es:",o:["Blockbusting","Canalización (steering)","Redlining","Exageración (puffing)"],e:"La canalización (steering) dirige a los compradores según una clase protegida. El blockbusting induce ventas por pánico; el redlining es discriminación del prestamista por zona."},
{t:"Vivienda Justa",q:"Decirles a los propietarios que deberían vender rápido porque familias de cierta etnia se están mudando al vecindario es:",o:["Canalización (steering)","Blockbusting (venta por pánico)","Redlining","Consejo de mercado permisible"],e:"El blockbusting (venta por pánico) consiste en inducir ventas al representar que la entrada de personas de una clase protegida afectará los valores. Es ilegal."},
{t:"Vivienda Justa",q:"Un prestamista que se niega a otorgar préstamos en ciertos vecindarios sin importar las calificaciones del solicitante está incurriendo en:",o:["Redlining","Canalización (steering)","Blockbusting","Almacenamiento de préstamos (warehousing)"],e:"El redlining es la negación discriminatoria de crédito basada en la ubicación o composición de un vecindario."},
{t:"Vivienda Justa",q:"La exención de venta por el propietario (FSBO) bajo la Ley de Vivienda Justa federal se pierde cuando:",o:["La vivienda vale más de $500,000","Se usa publicidad discriminatoria o participa un licenciatario de bienes raíces","El propietario también posee un condominio de alquiler","El comprador financia con FHA"],e:"Las exenciones nunca permiten la publicidad discriminatoria y desaparecen cuando participa un licenciatario. La ley de 1866 sigue prohibiendo la discriminación racial en todos los casos."},
{t:"Vivienda Justa",q:"Una queja bajo la Ley de Vivienda Justa federal debe presentarse ante HUD dentro de:",o:["90 días","6 meses","1 año","2 años"],e:"Las quejas se presentan ante HUD dentro de 1 año del acto alegado; las demandas civiles pueden presentarse dentro de 2 años."},
{t:"Ley de Financiamiento",q:"Bajo TILA (Regulación Z), ¿cuál declaración publicitaria desencadena los requisitos de divulgación completa?",o:["Pagos mensuales bajos","Solo $10,000 de pago inicial","Excelente financiamiento disponible","La tasa porcentual anual (APR)"],e:"Los términos desencadenantes incluyen el monto del pago inicial, los montos de los pagos, el número de pagos, el plazo o los cargos financieros. Las frases generales y el APR por sí solo no son desencadenantes."},
{t:"Ley de Financiamiento",q:"RESPA prohíbe principalmente:",o:["Tasas de interés altas","Comisiones ilícitas (kickbacks) y cargos no ganados en cierres de préstamos residenciales relacionados federalmente","Hipotecas de pago global (balloon)","Financiamiento del vendedor"],e:"RESPA aplica a préstamos relacionados federalmente sobre propiedades residenciales de una a cuatro unidades y prohíbe las comisiones ilícitas (kickbacks), los cargos no ganados y exigir una aseguradora de título en particular."},
{t:"Ley de Financiamiento",q:"Bajo TRID, el prestatario debe recibir la Divulgación de Cierre al menos:",o:["1 día hábil antes del cierre","3 días hábiles antes del cierre","7 días hábiles antes del cierre","En la mesa de cierre"],e:"La Divulgación de Cierre debe recibirse al menos 3 días hábiles antes de la consumación; la Estimación del Préstamo debe entregarse dentro de los 3 días hábiles posteriores a la solicitud."},
{t:"Arrendador-Inquilino",q:"Bajo la Ley de Arrendadores e Inquilinos Residenciales de la Florida, un arrendador que pretende reclamar parte de un depósito de seguridad debe enviar un aviso escrito dentro de:",o:["15 días","30 días","45 días","60 días"],e:"El aviso de reclamación debe enviarse por correo certificado dentro de los 30 días de que el inquilino desocupe. Si no se hace ninguna reclamación, el depósito debe devolverse dentro de 15 días."},
{t:"Divulgaciones",q:"¿Qué divulgación exige la ley de la Florida en todos los contratos de venta (y ciertos alquileres) de edificaciones?",o:["Historial de moho","Divulgación sobre gas radón","Estadísticas de criminalidad","Calificaciones de zonas escolares"],e:"Una declaración estatutaria de divulgación sobre gas radón debe aparecer en al menos un documento entregado en la firma del contrato de venta o antes de ella, o en alquileres que excedan 45 días."},
{t:"Divulgaciones",q:"Las reglas federales de divulgación sobre pintura a base de plomo aplican a viviendas residenciales construidas antes de:",o:["1968","1974","1978","1988"],e:"Los vendedores y arrendadores de viviendas anteriores a 1978 deben divulgar los peligros de plomo conocidos, entregar el folleto de la EPA y dar a los compradores una oportunidad de 10 días para una evaluación de riesgos."},
{t:"Divulgaciones",q:"Bajo Johnson v. Davis, un vendedor de vivienda en la Florida debe divulgar:",o:["Nada; aplica el principio de caveat emptor","Los hechos conocidos que afectan materialmente el valor de una propiedad residencial y que no son fácilmente observables","Solo los defectos sobre los que pregunte el comprador","Solo los defectos listados en el MLS"],e:"Este deber aplica a los vendedores y, por estatuto, a los licenciatarios en transacciones residenciales."},
{t:"Homestead",q:"La protección constitucional de vivienda familiar (homestead) de la Florida contra la venta forzosa cubre hasta:",o:["Un cuarto de acre en cualquier lugar","Medio acre dentro de un municipio o 160 acres fuera","Un acre en todo el estado","Diez acres en cualquier condado"],e:"La propiedad homestead está protegida contra la venta forzosa por la mayoría de los acreedores, con excepciones para los impuestos a la propiedad, las hipotecas y los gravámenes de construcción sobre la propiedad misma."},
{t:"Propiedad",q:"¿Cuál es la prueba más importante para determinar si un artículo es una instalación fija (fixture)?",o:["El costo del artículo","La intención de las partes","El tamaño del artículo","La antigüedad del artículo"],e:"Los tribunales consideran la intención, el método de fijación, la adaptación al bien inmueble y cualquier acuerdo entre las partes. La intención es la prueba determinante."},
{t:"Propiedad",q:"Los cultivos que se cultivan anualmente (emblementos) se clasifican como:",o:["Bienes inmuebles","Bienes muebles","Instalaciones fijas (fixtures)","Accesorios (appurtenances)"],e:"Los fructus industriales son bienes muebles incluso antes de la cosecha. Los árboles de crecimiento natural y las plantas perennes forman parte del bien inmueble."},
{t:"Propiedad",q:"¿Cuál NO forma parte del conjunto de derechos del propietario?",o:["Disposición","Exclusión","Tributación","Posesión"],e:"El conjunto de derechos incluye disposición, exclusión, goce, posesión y control. La tributación es un poder del gobierno, no un derecho de propiedad."},
{t:"Patrimonios",q:"La forma de propiedad más completa, de duración ilimitada y libremente transferible, es:",o:["Un patrimonio vitalicio (life estate)","El dominio pleno absoluto (fee simple)","Una tenencia por años","Un interés remanente"]},
{t:"Patrimonios",q:"O otorga un patrimonio vitalicio (life estate) a A, y el título pasa a B al fallecer A. B posee:",o:["Una reversión","Un interés remanente","Un arrendamiento (leasehold)","Dominio pleno absoluto (fee simple)"],e:"Cuando el título pasa a un tercero se crea un interés remanente. Si el título regresara al otorgante O, O tendría una reversión."},
{t:"Patrimonios",q:"Un inquilino cuyo contrato de arrendamiento ha vencido permanece en el apartamento sin el consentimiento del arrendador. El inquilino tiene:",o:["Una tenencia por años","Una tenencia a voluntad","Una tenencia por tolerancia","Un patrimonio de dominio absoluto (freehold)"],e:"Un inquilino remanente (holdover tenant) sin consentimiento es un inquilino por tolerancia, la forma más baja de interés de arrendamiento (leasehold)."},
{t:"Patrimonios",q:"Una tenencia por años:",o:["Requiere notificación para terminarse","Tiene una fecha definida de inicio y de terminación","Debe durar por lo menos un año","Es un patrimonio de dominio absoluto (freehold)"],e:"Termina automáticamente en la fecha final establecida, sin necesidad de notificación, y puede durar menos de un año a pesar de su nombre."},
{t:"Formas de Propiedad",q:"La característica distintiva de la tenencia conjunta es:",o:["Participaciones desiguales de propiedad","El derecho de supervivencia","Títulos separados para cada propietario","La conversión automática en tenencia por la totalidad al contraer matrimonio"],e:"La tenencia conjunta requiere las cuatro unidades (posesión, interés, tiempo, título). La participación del tenedor conjunto fallecido pasa a los tenedores conjuntos sobrevivientes."},
{t:"Formas de Propiedad",q:"La tenencia por la totalidad solo puede ser creada por:",o:["Socios de negocios","Un matrimonio","Padre e hijo","Cualesquiera dos personas naturales"],e:"Conlleva supervivencia automática, y ningún cónyuge puede transferir ni gravar la propiedad sin el otro."},
{t:"Formas de Propiedad",q:"Dos inversionistas no casados toman título conjuntamente sin indicar ninguna forma de propiedad. Ellos poseen como:",o:["Tenedores conjuntos","Tenedores por la totalidad","Tenedores en común","Tenedores a voluntad"],e:"La tenencia en común es la forma que se presume. Cada uno posee un interés indiviso, las participaciones pueden ser desiguales y no hay derecho de supervivencia."},
{t:"Formas de Propiedad",q:"El propietario de una unidad de condominio posee:",o:["Acciones corporativas y un arrendamiento propietario","Título de dominio pleno (fee simple) sobre la unidad más un interés indiviso en los elementos comunes","Solamente un interés de arrendamiento (leasehold)","Título sobre el terreno debajo de la unidad"],e:"Los condominios se crean registrando una declaración. Acciones más un arrendamiento propietario describe a una cooperativa."},
{t:"Formas de Propiedad",q:"El comprador de un apartamento cooperativo recibe:",o:["Una escritura de la unidad","Acciones de la corporación y un arrendamiento propietario","Título de dominio pleno (fee simple)","Un certificado de título"],e:"La corporación es dueña del bien inmueble; el interés del comprador es un bien mueble."},
{t:"Cargas",q:"Una servidumbre accesoria (easement appurtenant):",o:["Beneficia a una persona y no a una parcela de terreno","Corre con la tierra y se transfiere con el predio dominante","Termina cuando se vende el predio sirviente","No puede crearse por escrito"],e:"Beneficia al predio dominante y grava al predio sirviente, y pasa automáticamente con la transferencia de la parcela dominante."},
{t:"Cargas",q:"En la Florida, una servidumbre por prescripción requiere un uso continuo, abierto y adverso durante:",o:["7 años","10 años","20 años","30 años"],e:"Las servidumbres por prescripción requieren 20 años de uso adverso. La posesión adversa del título requiere solo 7 años, con título aparente (color of title) o pago de impuestos."},
{t:"Cargas",q:"La cerca de un vecino se extiende dos pies más allá de la línea del lote, sobre el terreno del propietario colindante. Esto es:",o:["Una servidumbre personal (in gross)","Una invasión (encroachment)","Una licencia (permiso)","Una restricción de escritura"],e:"Una invasión (encroachment) es una intrusión física no autorizada sobre el terreno ajeno, que típicamente se descubre mediante un levantamiento topográfico (survey)."},
{t:"Gravámenes",q:"¿Qué gravamen tiene prioridad sobre todos los demás sin importar la fecha de registro?",o:["Una primera hipoteca","Un gravamen por impuestos a la propiedad inmobiliaria","Un gravamen de construcción (mechanic's lien)","Un gravamen por sentencia judicial"],e:"Los gravámenes por impuestos a la propiedad y por contribuciones especiales son gravámenes superiores que se pagan primero en una ejecución hipotecaria."},
{t:"Gravámenes",q:"Un gravamen por sentencia judicial es un ejemplo de:",o:["Un gravamen específico sobre una sola propiedad","Un gravamen general que afecta todos los bienes del deudor en el condado donde se registra","Un gravamen voluntario","Un gravamen superior"],e:"Las hipotecas, los gravámenes por impuestos a la propiedad y los gravámenes de construcción son gravámenes específicos sobre una sola propiedad; las sentencias judiciales y los gravámenes del IRS son generales."},
{t:"Escrituras",q:"¿Cuál NO se requiere para que una escritura sea válida?",o:["La firma del otorgante","La firma del cesionario","Entrega y aceptación","Un otorgante legalmente competente"],e:"El cesionario no firma la escritura y ni siquiera necesita ser legalmente competente para recibir el título."},
{t:"Escrituras",q:"En la Florida, una escritura que transfiere bienes inmuebles debe ser firmada por el otorgante en presencia de:",o:["Solo un notario","Un testigo","Dos testigos","Tres testigos"],e:"La Florida exige dos testigos suscriptores de la firma del otorgante para que la transferencia por escritura sea válida."},
{t:"Escrituras",q:"La escritura que da al cesionario la mayor protección es la:",o:["Escritura de finiquito","Escritura de garantía especial","Escritura de compraventa (bargain and sale)","Escritura de garantía general"],e:"Contiene todas las garantías (posesión legítima o seisin, goce pacífico, contra cargas, garantía adicional y garantía perpetua) y cubre toda la cadena de título."},
{t:"Escrituras",q:"La escritura más comúnmente usada para eliminar una nube sobre el título, que transfiere solamente el interés que el otorgante pueda tener, es la:",o:["Escritura de garantía general","Escritura de finiquito","Escritura de garantía especial","Escritura de tutor (guardian's deed)"],e:"Una escritura de finiquito no contiene garantías ni avales de ningún tipo."},
{t:"Título",q:"Para adquirir título por posesión adversa en la Florida, la posesión debe ser abierta, notoria y hostil durante por lo menos:",o:["5 años","7 años","10 años","20 años"],e:"Siete años, con título aparente (color of title) o con pago de los impuestos a la propiedad, junto con los demás requisitos legales."},
{t:"Título",q:"Registrar una escritura en los registros públicos del condado proporciona:",o:["Notificación real","Notificación implícita (constructiva)","Notificación tácita","Ninguna notificación legal"],e:"El registro da notificación implícita (constructiva o legal) al mundo. La notificación real proviene del conocimiento directo, como inspeccionar la propiedad."},
{t:"Título",q:"Una póliza de seguro de título del propietario:",o:["Requiere una prima anual","Protege contra defectos de título cubiertos que ocurrieron antes de la fecha de la póliza","Cubre defectos que el propietario cause después del cierre","Se transfiere automáticamente al próximo comprador"],e:"Una prima única compra protección contra defectos pasados no descubiertos, hasta el monto de la póliza."},
{t:"Título",q:"En la Florida, la porción electiva del cónyuge sobreviviente sobre el patrimonio del cónyuge fallecido es:",o:["10%","30%","50%","100%"],e:"El cónyuge sobreviviente puede elegir tomar el 30% del patrimonio electivo sin importar los términos del testamento."},
{t:"Descripciones Legales",q:"Una descripción por medidas y colindancias debe:",o:["Hacer referencia a un plano (plat) registrado","Comenzar y regresar al punto de partida (POB)","Usar líneas de sección y de municipio de agrimensura (township)","Incluir la dirección de la calle"],e:"El límite debe cerrarse regresando al POB, siguiendo monumentos, distancias y rumbos de brújula."},
{t:"Descripciones Legales",q:"Una sección de terreno en el sistema de agrimensura gubernamental contiene:",o:["36 millas cuadradas","640 acres","160 acres","43,560 pies cuadrados"],e:"Una sección es una milla cuadrada, o 640 acres. Un municipio de agrimensura (township) contiene 36 secciones; un acre tiene 43,560 pies cuadrados."},
{t:"Descripciones Legales",q:"El método de descripción legal de lote y manzana (lot and block) se basa en:",o:["Un plano (plat) registrado","Monumentos y rumbos de brújula","Meridianos principales y líneas base","Números de parcela del tasador"],e:"El terreno subdividido se describe por los números de lote y manzana que aparecen en un plano (plat) registrado en los registros públicos."},
{t:"Contratos",q:"Para ser ejecutable ante un tribunal, un contrato de compraventa de bienes inmuebles debe:",o:["Estar notarizado","Estar registrado","Constar por escrito y estar firmado por las partes","Ser presenciado por dos testigos"],e:"El estatuto de fraudes exige que los contratos de compraventa y los arrendamientos de más de un año consten por escrito. Los contratos de listado no necesitan ser escritos para ser válidos."},
{t:"Contratos",q:"Un contrato de opción es:",o:["Bilateral, obliga a ambas partes","Unilateral, obliga solamente al otorgante de la opción (propietario)","Nulo a menos que se registre","Una oferta que puede retirarse en cualquier momento"],e:"El beneficiario de la opción paga una contraprestación por el derecho, pero no la obligación, de comprar dentro del período de la opción."},
{t:"Contratos",q:"Un vendedor responde a la oferta de un comprador cambiando el precio. La oferta original del comprador queda:",o:["Todavía abierta para su aceptación","Terminada por la contraoferta","Aceptada automáticamente","Convertida en una opción"],e:"Una contraoferta rechaza y extingue la oferta original; el oferente original se convierte en el nuevo destinatario de la oferta."},
{t:"Contratos",q:"Una orden judicial que obliga a un vendedor incumplidor a transferir la propiedad según lo acordado se llama:",o:["Rescisión","Daños liquidados","Cumplimiento específico","Novación"],e:"Como el terreno es único, los tribunales pueden ordenar el cumplimiento específico en lugar de limitar al comprador a una indemnización monetaria."},
{t:"Contratos",q:"Sustituir a la parte original por un nuevo obligado, liberando de responsabilidad a la parte original, es:",o:["Cesión","Novación","Subordinación","Subrogación"],e:"Bajo una simple cesión, la parte original puede seguir siendo responsable de manera secundaria; la novación extingue la obligación anterior."},
{t:"Listados",q:"Bajo un listado de derecho exclusivo de venta, el corredor gana la comisión:",o:["Solo si el corredor encuentra personalmente al comprador","Si cualquier persona, incluido el propietario, vende la propiedad durante el plazo del listado","Solo si la propiedad se vende al precio de lista completo","Solo después de que el comprador tome ocupación"],e:"Este listado da al corredor la protección más fuerte. Bajo un listado de agencia exclusiva, el propietario puede vender personalmente sin pagar."},
{t:"Listados",q:"Bajo un listado de agencia exclusiva, el propietario:",o:["Puede vender la propiedad personalmente sin deber comisión","Debe pagar la comisión sin importar quién venda","Puede listar simultáneamente con muchos corredores","No puede cancelar el listado"],e:"Se emplea a un solo corredor, pero el propietario se reserva el derecho de vender sin obligación. Un listado abierto sí puede darse a múltiples corredores."},
{t:"Listados",q:"Un contrato de listado residencial por escrito en la Florida debe:",o:["Estar registrado","Contener una fecha de vencimiento definida y ninguna cláusula de renovación automática","Durar por lo menos seis meses","Estar notarizado"],e:"También debe estar firmado por el vendedor, y se le debe entregar una copia al vendedor dentro de las 24 horas siguientes a la firma."},
{t:"Hipotecas",q:"La Florida es un estado de teoría de gravamen, lo que significa que:",o:["El prestamista retiene el título legal hasta que se pague el préstamo","El prestatario retiene el título y el prestamista tiene un gravamen sobre la propiedad","La ejecución hipotecaria es no judicial","Un fideicomisario retiene el título para el prestamista"],e:"En los estados de teoría de título, los prestamistas retienen el título mediante una escritura de fideicomiso; en la Florida, la hipoteca crea solamente un gravamen."},
{t:"Hipotecas",q:"El documento que contiene la promesa personal del prestatario de pagar la deuda es:",o:["La hipoteca","El pagaré","La escritura","La cancelación de hipoteca"],e:"El pagaré es la evidencia de la deuda; la hipoteca compromete la propiedad como garantía de ese pagaré."},
{t:"Hipotecas",q:"La cláusula que permite al prestamista exigir el pago total si la propiedad se vende es la:",o:["Cláusula de aceleración","Cláusula de vencimiento por venta (enajenación)","Cláusula de anulación (defeasance)","Cláusula de subordinación"],e:"La aceleración opera en caso de incumplimiento; la cláusula de anulación (defeasance) extingue el gravamen cuando la deuda se paga por completo."},
{t:"Hipotecas",q:"Un comprador que adquiere una propiedad \"sujeto a\" una hipoteca existente:",o:["Se hace personalmente responsable de la deuda","No es personalmente responsable; el vendedor sigue siendo responsable del pagaré","Libera al vendedor de toda responsabilidad","Debe calificar con el prestamista"],e:"En una asunción, el comprador se hace personalmente responsable de la deuda; solo una novación libera al prestatario original."},
{t:"Hipotecas",q:"La ejecución hipotecaria en la Florida es:",o:["No judicial, por poder de venta","Un proceso judicial a través de los tribunales","Conducida por un fideicomisario","Prohibida en propiedades de inversión"],e:"La Florida exige la ejecución hipotecaria judicial. El prestatario puede ejercer el derecho de redención pagando la deuda en cualquier momento antes de la venta de ejecución."},
{t:"Hipotecas",q:"Un aviso registrado de que hay una demanda pendiente que puede afectar el título de una propiedad es un:",o:["Lis pendens","Orden de ejecución","Sentencia por deficiencia","Cancelación de hipoteca"],e:"El lis pendens da notificación implícita (constructiva) de un litigio pendiente, como una acción de ejecución hipotecaria."},
{t:"Financiamiento",q:"¿Cuál afirmación sobre los programas de préstamos del gobierno es correcta?",o:["La FHA otorga préstamos directamente a los compradores","La FHA asegura préstamos y la VA garantiza préstamos","La VA asegura préstamos y la FHA los garantiza","Ambas agencias compran préstamos en el mercado secundario"],e:"La FHA asegura a los prestamistas contra el incumplimiento (el prestatario paga el MIP); la VA garantiza la porción superior de los préstamos de los veteranos elegibles, a menudo sin cuota inicial."},
{t:"Financiamiento",q:"En los préstamos convencionales, el seguro hipotecario privado generalmente se requiere cuando la relación préstamo-valor (LTV) excede:",o:["70%","80%","90%","95%"],e:"El PMI protege al prestamista en préstamos convencionales de LTV alto y está sujeto a cancelación a medida que crece el valor líquido (equity) del propietario."},
{t:"Financiamiento",q:"La tasa de interés de una hipoteca de tasa ajustable se determina por:",o:["Índice más margen","Tasa preferencial (prime) menos puntos","Margen menos topes","Tasa de descuento más cargos de originación"],e:"La tasa flota con un índice publicado; se le suma el margen fijo del prestamista. Los topes limitan los cambios periódicos y de por vida."},
{t:"Financiamiento",q:"Un desarrollador financia una subdivisión completa con una sola hipoteca que cubre todos los lotes y obtiene liberaciones a medida que se venden los lotes individuales. Esto es una:",o:["Hipoteca de paquete (package) con cláusula de escalación","Hipoteca general (blanket) con cláusula de liberación parcial","Hipoteca envolvente (wraparound)","Hipoteca abierta (open-end)"],e:"Una hipoteca general (blanket) cubre múltiples parcelas; la cláusula de liberación parcial libera los lotes del gravamen a medida que se pagan."},
{t:"Financiamiento",q:"Una hipoteca garantizada por el bien inmueble más los electrodomésticos y el mobiliario es una:",o:["Hipoteca general (blanket)","Hipoteca de paquete (package)","Hipoteca de dinero de compra","Hipoteca de participación (participation)"],e:"Las hipotecas de paquete incluyen bienes muebles, algo común en las ventas de condominios amueblados."},
{t:"Financiamiento",q:"Cuando un vendedor financia parte del precio de compra y recibe una hipoteca del comprador, esto es una:",o:["Hipoteca de dinero de compra","Fideicomiso envolvente (wraparound)","Préstamo puente","Hipoteca inversa"],e:"El financiamiento del vendedor garantizado por la propiedad vendida es una hipoteca de dinero de compra."},
{t:"Financiamiento",q:"La función principal del mercado hipotecario secundario es:",o:["Otorgar préstamos directamente a los consumidores","Comprar y vender préstamos hipotecarios existentes, proporcionando liquidez a los prestamistas","Asegurar préstamos contra el incumplimiento","Fijar tasas de interés máximas"],e:"Fannie Mae y Freddie Mac compran préstamos a los originadores; Ginnie Mae garantiza valores respaldados por hipotecas."},
{t:"Financiamiento",q:"La relación de obligaciones totales (TOR) de referencia para un préstamo convencional es:",o:["28%","31%","36%","43%"],e:"Referencias convencionales: 28% para la relación de gastos de vivienda, 36% para las obligaciones totales. Las referencias de la FHA son 31% y 43%."},
{t:"Financiamiento",q:"Los prestamistas cobran puntos de descuento para:",o:["Cubrir los costos del avalúo","Aumentar el rendimiento efectivo del préstamo","Reducir el saldo de principal del prestatario","Pagar la comisión del corredor"],e:"Un punto equivale al 1% del monto del préstamo. Como regla práctica, cada punto aumenta el rendimiento del prestamista en aproximadamente un octavo del uno por ciento."},
{t:"Avalúo",q:"Las cuatro características necesarias para que algo tenga valor son:",o:["Demanda, utilidad, escasez y transferibilidad","Densidad, uso, tamaño y título","Deseo, utilidad práctica, oferta y tenencia","Demanda, singularidad, estabilidad y transferencia"],e:"Se recuerdan con la sigla DUST. Las cuatro deben estar presentes para que exista el valor de mercado."},
{t:"Avalúo",q:"El principio de avalúo que establece que un comprador no pagará por una propiedad más que el costo de adquirir un sustituto igualmente deseable es:",o:["Anticipación","Sustitución","Conformidad","Contribución"],e:"La sustitución es el fundamento del enfoque de comparación de ventas."},
{t:"Avalúo",q:"El uso más alto y mejor de un terreno debe ser:",o:["El uso actual de la propiedad","Legalmente permisible, físicamente posible, financieramente factible y máximamente productivo","El uso que produzca la estructura más grande","Lo que el propietario prefiera"]},
{t:"Avalúo",q:"En el enfoque de comparación de ventas, un comparable tiene piscina y la propiedad en cuestión no. El tasador:",o:["Suma el valor de la piscina a la propiedad en cuestión","Resta el valor contributivo de la piscina del precio de venta del comparable","Ignora la diferencia","Resta el valor de la piscina de la propiedad en cuestión"],e:"Los ajustes siempre se hacen al comparable, nunca a la propiedad en cuestión: si el comparable es mejor, se resta; si es inferior, se suma."},
{t:"Avalúo",q:"La pérdida de valor causada por factores externos a la propiedad, como un vertedero cercano, es:",o:["Deterioro físico","Obsolescencia funcional","Obsolescencia externa (económica)","Depreciación subsanable"],e:"La obsolescencia externa siempre es insubsanable porque el propietario no puede controlar las causas fuera del predio. Una distribución interior anticuada es obsolescencia funcional."},
{t:"Avalúo",q:"Al calcular el ingreso neto de operación, ¿cuál NO se deduce del ingreso bruto efectivo?",o:["Impuestos a la propiedad","Costos de mantenimiento","Servicio de la deuda hipotecaria","Seguro contra riesgos"],e:"El NOI excluye el servicio de la deuda, los impuestos sobre la renta y la depreciación. Las pérdidas por vacantes y falta de cobro se deducen del ingreso bruto potencial para obtener el ingreso bruto efectivo."},
{t:"Avalúo",q:"El multiplicador de renta bruta (GRM) se calcula dividiendo:",o:["La renta anual entre el precio de venta","El precio de venta entre la renta bruta mensual","El NOI entre la tasa de capitalización","La renta mensual entre los gastos de operación"],e:"El GRM usa la renta mensual; el multiplicador de ingreso bruto (GIM) usa el ingreso anual."},
{t:"Avalúo",q:"Un avalúo para una transacción relacionada federalmente debe ser realizado por:",o:["Cualquier licenciatario de bienes raíces","Un tasador certificado o licenciado por el estado","El oficial de préstamos del prestamista","Un corredor aprobado por la FREC"],e:"Los licenciatarios de bienes raíces pueden preparar CMA y opiniones de precio del corredor por compensación, pero no pueden llamarlos avalúos, y deben seguir las normas USPAP al realizar avalúos."},
{t:"Corretaje de Negocios",q:"En la venta de un negocio, el activo intangible que surge de la reputación y de una clientela establecida es:",o:["La plusvalía (goodwill)","El bien mueble (chattel)","El capital de trabajo","El inventario"],e:"El valor de negocio en marcha incluye los activos tangibles más los intangibles como la plusvalía (goodwill)."},
{t:"Impuestos",q:"Los impuestos ad valorem a la propiedad se basan en:",o:["El ingreso del propietario","El valor justo (de mercado) de la propiedad tasado al 1 de enero","El precio de compra original","Solamente los pies cuadrados"],e:"El tasador de propiedades del condado tasa el valor cada 1 de enero; ad valorem significa según el valor."},
{t:"Impuestos",q:"Un cobro único aplicado solamente a las propiedades que se benefician de una mejora pública específica, como una nueva línea de alcantarillado, es:",o:["Una contribución especial (special assessment)","Un aumento de milaje","Un impuesto ad valorem","Un impuesto de estampillas documentales"],e:"Las contribuciones especiales son gravámenes específicos e involuntarios que se prorratean según el beneficio recibido."},
{t:"Impuestos",q:"La disposición Save Our Homes de la Florida limita los aumentos anuales del valor tasado de una propiedad con homestead a:",o:["3% o el cambio en el índice de precios al consumidor (CPI), lo que sea menor","5% fijo","10% fijo","No aplica ningún límite"],e:"El límite aplica a la propiedad con exención de vivienda familiar (homestead); los ahorros acumulados pueden transferirse a un nuevo homestead dentro de los límites establecidos por ley."},
{t:"Impuestos",q:"¿Cuánta ganancia puede excluir un matrimonio que declara en conjunto por la venta de una residencia principal?",o:["$125,000","$250,000","$500,000","$1,000,000"],e:"La Sección 121 permite $500,000 para declarantes conjuntos ($250,000 individual) si fueron propietarios de la vivienda y la usaron como residencia principal durante 2 de los 5 años anteriores."},
{t:"Impuestos",q:"Para efectos del impuesto federal sobre la renta, los edificios residenciales de alquiler se deprecian en:",o:["15 años","27.5 años","39 años","50 años"],e:"La propiedad no residencial usa 39 años. El terreno nunca es depreciable."},
{t:"Impuestos",q:"En un intercambio de propiedades similares de la Sección 1031, el dinero u otra propiedad no similar que se recibe se llama:",o:["\"Boot\", y es gravable","Base fiscal","Valor líquido libre de impuestos","Plusvalía (goodwill)"],e:"Los intercambios 1031 difieren la ganancia sobre bienes inmuebles de inversión o de negocio que califiquen, pero el boot recibido se grava en el año del intercambio."},
{t:"Planificación",q:"Las ordenanzas de zonificación son un ejercicio de:",o:["Dominio eminente, que requiere compensación","El poder de policía, que no requiere compensación","Reversión al estado (escheat)","Derechos ribereños"],e:"El poder de policía regula por la salud, la seguridad y el bienestar sin compensación. El dominio eminente toma propiedad para uso público con compensación justa mediante la expropiación (condemnation)."},
{t:"Planificación",q:"Un propietario cuyo lote de forma irregular no puede cumplir con los requisitos de retiro (setback) puede buscar alivio mediante:",o:["Una excepción especial","Una variación (variance)","Una enmienda al plan integral","Un permiso de uso no conforme"],e:"La variación (variance) alivia una dificultad excesiva única del terreno. La excepción especial es un uso ya permitido por la ordenanza sujeto a condiciones."},
{t:"Planificación",q:"Una tienda que existía legalmente antes de que su área fuera rezonificada como residencial puede seguir operando como:",o:["Una variación (variance)","Una excepción especial","Un uso no conforme","Una zonificación puntual (spot zoning)"],e:"Los usos no conformes legales (protegidos por derechos adquiridos, grandfathered) pueden continuar, pero normalmente no pueden ampliarse ni reconstruirse si son destruidos."},
{t:"Planificación",q:"Una franja de parque que separa un vecindario residencial de un distrito industrial es:",o:["Una zona de amortiguamiento","Un retiro (setback)","Un plano (plat)","Una servidumbre personal (in gross)"],e:"Las zonas de amortiguamiento suavizan la transición entre usos de suelo incompatibles."},
{t:"Medio Ambiente",q:"El asbesto representa el mayor peligro para la salud cuando está:",o:["Encapsulado","Friable (que se desmorona y queda en el aire)","Cubierto con pintura","Sellado detrás de paneles de yeso (drywall)"],e:"El asbesto friable libera fibras inhalables. La encapsulación es un método común de remediación. El gas radón, en cambio, es un gas radiactivo natural que entra desde el suelo."},
{t:"Comisión",q:"Una casa se vende por $285,000 con una comisión del 6% dividida 50/50 entre la oficina de listado y la oficina de venta. El asociado de ventas de la oficina de venta recibe el 60% de la parte de su oficina. ¿Cuánto gana el asociado?",o:["$4,275","$5,130","$8,550","$10,260"],e:"$285,000 x 0.06 = $17,100 en total. Parte de la oficina: $17,100 x 0.50 = $8,550. Asociado: $8,550 x 0.60 = $5,130."},
{t:"Comisión",q:"Una propiedad se vende por $350,000 con una comisión del 6%. La oficina de listado retiene el 55% y la oficina de venta el 45%. El asociado de venta tiene una división del 50% con su corredor. El asociado de venta gana:",o:["$4,725","$5,775","$9,450","$11,550"],e:"$350,000 x 0.06 = $21,000. Oficina de venta: $21,000 x 0.45 = $9,450. Asociado: $9,450 x 0.50 = $4,725."},
{t:"Área",q:"Una parcela rectangular mide 660 pies por 660 pies. ¿Cuántos acres contiene?",o:["5 acres","8 acres","10 acres","15 acres"],e:"660 x 660 = 435,600 pies cuadrados. 435,600 / 43,560 = 10 acres."},
{t:"Área",q:"Un lote que mide 90 pies por 120 pies se vende a $12.50 por pie cuadrado. El precio es:",o:["$112,500","$121,500","$135,000","$150,000"],e:"90 x 120 = 10,800 pies cuadrados. 10,800 x $12.50 = $135,000."},
{t:"Descripciones Legales",q:"¿Cuántos acres hay en el 1/4 SE del 1/4 NO de una sección?",o:["10 acres","40 acres","80 acres","160 acres"],e:"640 / 4 = 160; 160 / 4 = 40 acres. Multiplique los denominadores (4 x 4 = 16) y divida 640 entre 16."},
{t:"Impuestos de Transferencia",q:"El impuesto de estampillas documentales sobre la escritura en una venta de $310,000 (fuera de Miami-Dade) es:",o:["$1,085","$1,550","$2,170","$3,100"],e:"$310,000 / $100 = 3,100 unidades gravables x $0.70 = $2,170. Cuando sea necesario, redondee el precio hacia arriba al siguiente múltiplo de $100."},
{t:"Impuestos de Transferencia",q:"Un comprador obtiene una nueva hipoteca de $200,000. El total de impuestos estatales sobre el pagaré y la hipoteca (estampillas documentales sobre el pagaré más el impuesto intangible) es:",o:["$400","$700","$1,100","$1,400"],e:"Estampillas sobre el pagaré: 2,000 unidades x $0.35 = $700. Impuesto intangible: $200,000 x 0.002 = $400. Total $1,100."},
{t:"Prorrateos",q:"Los impuestos anuales a la propiedad son $3,650 ($10/día en un año de 365 días). El cierre es el 15 de octubre, los impuestos están sin pagar y el día del cierre pertenece al comprador. El asiento de prorrateo es:",o:["$780 crédito al vendedor","$2,870 débito al vendedor, crédito al comprador","$2,880 débito al comprador","$3,650 débito al vendedor"],e:"El vendedor debe del 1 de enero al 14 de octubre = 287 días x $10 = $2,870, que se debitan al vendedor y se acreditan al comprador, quien pagará la factura completa."},
{t:"Matemática Hipotecaria",q:"Un préstamo de $180,000 al 6% de interés anual tiene un pago mensual de $1,079.19. ¿Cuánto del primer pago es interés?",o:["$900.00","$1,079.19","$179.19","$180.00"],e:"$180,000 x 0.06 = $10,800 / 12 = $900 de interés. Reducción del principal: $1,079.19 - $900 = $179.19."},
{t:"Matemática Hipotecaria",q:"El precio de compra es $250,000 y el avalúo resulta en $245,000. Con un préstamo con una relación préstamo-valor (LTV) del 80%, el monto máximo del préstamo es:",o:["$200,000","$196,000","$186,000","$204,000"],e:"El LTV se basa en el menor entre el precio y el valor de avalúo: $245,000 x 0.80 = $196,000."},
{t:"Matemática Hipotecaria",q:"Un prestatario paga 2 puntos de descuento sobre un préstamo de $240,000. El cargo es:",o:["$2,400","$4,800","$7,200","$9,600"],e:"Cada punto es el 1% del monto del préstamo: $240,000 x 0.02 = $4,800."},
{t:"Calificación",q:"Un comprador gana $72,000 al año y el pago PITI propuesto es $1,560. La relación de gastos de vivienda es:",o:["24%","26%","28%","31%"],e:"Ingreso mensual: $72,000 / 12 = $6,000. $1,560 / $6,000 = 0.26 = 26%."},
{t:"Inversión",q:"Una propiedad produce $36,000 de ingreso neto de operación (NOI) y se vende por $450,000. La tasa de capitalización es:",o:["6%","7%","8%","9%"],e:"Tasa = Ingreso / Valor: $36,000 / $450,000 = 8%."},
{t:"Inversión",q:"Un inversionista requiere un rendimiento del 9%. Un edificio genera un NOI de $27,000. El precio máximo justificado es:",o:["$243,000","$270,000","$300,000","$330,000"],e:"Valor = Ingreso / Tasa: $27,000 / 0.09 = $300,000."},
{t:"Inversión",q:"Una casa se vende por $240,000 y se renta por $2,000 al mes. El multiplicador de renta bruta (GRM) es:",o:["100","110","120","144"],e:"GRM = precio / renta mensual = $240,000 / $2,000 = 120."},
{t:"Inversión",q:"Un arrendamiento de un local comercial estipula una renta base de $1,200 al mes más el 3% de las ventas brutas que excedan $500,000. Las ventas fueron $740,000. La renta anual total es:",o:["$14,400","$21,600","$22,200","$36,600"],e:"Base: $1,200 x 12 = $14,400. Porcentaje: ($740,000 - $500,000) x 0.03 = $7,200. Total $21,600."},
{t:"Matemática de Avalúo",q:"El costo de reproducción nuevo de un edificio es $400,000, la edad efectiva es 10 años y la vida económica total es 50 años. El terreno vale $100,000. El valor según el enfoque de costo es:",o:["$320,000","$400,000","$420,000","$500,000"],e:"Depreciación: 10/50 = 20% x $400,000 = $80,000. Edificio: $320,000 + terreno $100,000 = $420,000."},
{t:"Porcentajes",q:"Una casa se vende por $322,000, que es 15% más de lo que el propietario pagó por ella. El precio original fue:",o:["$273,700","$280,000","$285,000","$370,300"],e:"$322,000 / 1.15 = $280,000. Divida entre (100% + 15%); no reste el 15% del precio de venta."},
{t:"Neto del Vendedor",q:"Un vendedor desea recibir un neto de $282,000 después de pagar una comisión del 6%. Ignorando otros costos, el precio de venta debe ser:",o:["$296,000","$298,920","$300,000","$316,800"],e:"Precio = neto / (1 - 0.06) = $282,000 / 0.94 = $300,000."},
{t:"Impuesto a la Propiedad",q:"Una propiedad tiene un valor gravable de $130,000 y la tasa total de milaje es 20 mills. Los impuestos anuales son:",o:["$2,340","$2,600","$3,600","$2,860"],e:"20 mills = 0.020. $130,000 x 0.020 = $2,600."},
];
